import { z } from 'zod';
import { validateCoupon } from './couponClient';

export const checkoutSchema = z.object({
  email: z.string().email('Enter a valid email'),
  address1: z.string().min(1,'Address required'),
  zip: z.string().regex(/^\d{5}(-\d{4})?$/,'Invalid ZIP'),
  coupon: z.string().optional()
}).superRefine(async (val, ctx) => {
  if(!val.coupon) return;
  const res = await validateCoupon(val.coupon);
  if(!res.valid){
    ctx.addIssue({ code: z.ZodIssueCode.custom, path:['coupon'], message: res.reason ?? 'Invalid coupon' });
  }
});
export type CheckoutValues = z.infer<typeof checkoutSchema>;

const cache = new Map<string,{at:number;val:{valid:boolean;reason?:string;discount?:number}}>();
const inflight = new Map<string,Promise<any>>();
export async function validateCoupon(code:string){
  const key=code.trim().toUpperCase();
  const hit=cache.get(key);
  if(hit && Date.now()-hit.at<30000) return hit.val;
  if(inflight.has(key)) return inflight.get(key)!;
  const p=fetch('/api/coupon/validate?code='+encodeURIComponent(key))
    .then(r=>r.json())
    .then(val=>{ cache.set(key,{at:Date.now(),val}); inflight.delete(key); return val; })
    .catch(e=>{ inflight.delete(key); throw e; });
  inflight.set(key,p);
  return p;
}

