import { NextRequest } from 'next/server';
import { redis } from '@/lib/redis';
import { db } from '@/lib/db';
import { RESERVED } from '@/lib/reserved';

export async function GET(req:NextRequest){
  const slug=(req.nextUrl.searchParams.get('slug')||'').toLowerCase();
  if(!/^[a-z0-9-]{3,32}$/.test(slug)) return Response.json({state:'invalid'});
  if(RESERVED.has(slug)) return Response.json({state:'reserved'});
  const exists=await db.workspace.findUnique({where:{slug},select:{id:true}});
  if(exists) return Response.json({state:'taken'});
  const heldBy=await redis.get('ws:claim:'+slug);
  if(heldBy) return Response.json({state:'taken'});
  return Response.json({state:'available'});
}

import { redis } from '@/lib/redis';
import { db } from '@/lib/db';
import { getSession } from '@/lib/auth';

export async function POST(req:Request){
  const { slug }=await req.json();
  const sid=(await getSession())?.id ?? crypto.randomUUID();
  const claimKey='ws:claim:'+slug;
  // soft-reserve so concurrent live-checks see it as taken
  const ok=await redis.set(claimKey, sid, {NX:true, EX:15});
  try{
    const ws=await db.workspace.create({data:{slug, ownerSession:sid}});
    return Response.json({id:ws.id});
  }catch(e:any){
    if(e.code==='P2002') return Response.json({field:'slug',error:'taken'},{status:409});
    throw e;
  }finally{
    if(ok) await redis.del(claimKey);
  }
}

