export async function submitKyc(draft:any){
  const country=draft.country;
  for(const key of ['identity','address'] as const){
    const r=await stepSchemas(country)[key].safeParseAsync(draft);
    if(!r.success) return {ok:false, field:r.error.issues[0].path[0]};
  }
  await db.kycApplication.create({data:{
    encrypted: encrypt(JSON.stringify({taxId:draft.taxId,dob:draft.dob})),
    rulesetVersion: RULESET_VERSION,
    country
  }});
  return {ok:true};
}

