import { ref } from 'vue';
import { useComments } from '@/stores/comments';
export function useOptimisticEdit(id:string){
  const store=useComments();
  const draft=ref(store.byId[id].body);
  const status=ref<'idle'|'saving'|'blocked'|'offline'|'review'>('idle');
  let key:string|null=null;
  async function save(){
    if(status.value==='saving') return;
    key=key ?? crypto.randomUUID(); // stable across retries -> idempotent
    const snap=store.snapshot(id);
    store.applyOptimistic(id, draft.value);
    status.value='saving';
    try{
      const r=await fetch(`/api/comments/${id}`,{method:'PUT',headers:{'Idempotency-Key':key,'content-type':'application/json'},body:JSON.stringify({body:draft.value})});
      const j=await r.json();
      if(j.verdict==='blocked'){ store.revert(snap); status.value='blocked'; return; }
      if(j.verdict==='needs_review'){ status.value='review'; }
      store.byId[id]=j.comment; key=null; status.value='idle';
    }catch(e){ store.revert(snap); status.value='offline'; }
  }
  return { draft, status, save };
}

