import Ajv from 'ajv';
import { useState } from 'react';
const ajv=new Ajv({allErrors:true,$data:true});
export function DynamicForm({schema, ui, onSubmit}:{schema:any;ui:Record<string,any>;onSubmit:(v:any)=>void}){
  const [values,setValues]=useState<any>({});
  const [errors,setErrors]=useState<Record<string,string>>({});
  const validate=ajv.compile(schema);
  function submit(e:React.FormEvent){
    e.preventDefault();
    if(validate(values)){ setErrors({}); onSubmit(values); return; }
    const errs:Record<string,string>={};
    (validate.errors||[]).forEach(er=>{ errs[er.instancePath.slice(1)||er.params.missingProperty]=er.message||'invalid'; });
    setErrors(errs);
  }
  const visible=(k:string)=> ui[k]?.showIf? ui[k].showIf(values): true;
  return <form onSubmit={submit}>{Object.keys(schema.properties).filter(visible).map(k=>(
    <div key={k}><label>{ui[k]?.label||k}</label>
      <input value={values[k]??''} onChange={e=>setValues({...values,[k]:e.target.value})}/>
      <span>{errors[k]}</span></div>))}
    <button>Submit</button></form>;
}

