import Ajv from 'ajv';
import { db } from './db';
const ajv=new Ajv({allErrors:true});
export async function validateIntake(formId:string, version:number, submission:any){
  const rec=await db.formSchema.findUnique({where:{formId_version:{formId,version}}});
  const validate=ajv.compile(rec.schema);
  if(!validate(submission)) return {ok:false, errors:validate.errors};
  const phi:string[]=rec.schema['x-phi']||[];
  const analyticsSafe=Object.fromEntries(Object.entries(submission).filter(([k])=>!phi.includes(k)));
  await db.analytics.event('intake_submitted', analyticsSafe); // PHI excluded
  return {ok:true};
}

