import { z } from 'zod';
export const bookingSchema=z.object({
  startUtc: z.string().datetime(),
  endUtc: z.string().datetime()
}).superRefine((v,ctx)=>{
  const s=new Date(v.startUtc).getTime(), e=new Date(v.endUtc).getTime();
  if(e<=s) ctx.addIssue({code:'custom',path:['endUtc'],message:'End must be after start'});
  const hrs=(e-s)/3.6e6;
  if(hrs<2) ctx.addIssue({code:'custom',path:['endUtc'],message:'Window must be at least 2h'});
  if(hrs>72) ctx.addIssue({code:'custom',path:['endUtc'],message:'Window cannot exceed 72h'});
});
export type Booking=z.infer<typeof bookingSchema>;

import { useState, useRef } from 'react';
import { useDebouncedCallback } from 'use-debounce';
export function useAvailability(){
  const [state,setState]=useState<'idle'|'checking'|'available'|'none'>('idle');
  const ctrl=useRef<AbortController|null>(null);
  const reqId=useRef(0);
  const check=useDebouncedCallback(async (startUtc:string,endUtc:string)=>{
    ctrl.current?.abort();
    const ac=new AbortController(); ctrl.current=ac;
    const myId=++reqId.current;
    setState('checking');
    try{
      const r=await fetch(`/api/capacity?start=${startUtc}&end=${endUtc}`,{signal:ac.signal});
      const j=await r.json();
      if(myId!==reqId.current) return; // a newer request superseded us
      setState(j.trucks>0?'available':'none');
    }catch(e){ if((e as any).name!=='AbortError') setState('idle'); }
  },300);
  return { state, check };
}

