def validate_range(start_utc:str,end_utc:str):
    s=datetime.fromisoformat(start_utc); e=datetime.fromisoformat(end_utc)
    if e<=s: raise HTTPException(422,'End must be after start')
    hrs=(e-s).total_seconds()/3600
    if hrs<2 or hrs>72: raise HTTPException(422,'Window must be 2-72h')

