func (s *Server) UpdateProfile(ctx context.Context, r *pb.UpdateProfileRequest) (*pb.Profile, error){
  p:=r.GetProfile()
  if !strings.Contains(p.Email, "@") { return nil, status.Error(codes.InvalidArgument, "bad email") }
  // validates whole message even for partial updates; ignores r.UpdateMask
  if p.Phone=="" { return nil, status.Error(codes.InvalidArgument, "phone required") }
  return s.store.Save(ctx, p)
}

syntax="proto3";
import "buf/validate/validate.proto";
message Profile {
  string email = 1 [(buf.validate.field).string.email = true];
  string phone = 2 [(buf.validate.field).string.pattern = "^\\+?[1-9]\\d{7,14}$"];
  string display_name = 3 [(buf.validate.field).string.min_len = 1];
  int64 version = 4;
}
message UpdateProfileRequest { Profile profile=1; google.protobuf.FieldMask update_mask=2; }

func (s *Server) UpdateProfile(ctx context.Context, r *pb.UpdateProfileRequest) (*pb.Profile, error){
  v,_:=protovalidate.New()
  mask:=r.GetUpdateMask()
  fields:=mask.GetPaths()
  if len(fields)==0 { // backward-compat full validation
    if err:=v.Validate(r.Profile); err!=nil { return nil, status.Error(codes.InvalidArgument, err.Error()) }
  } else {
    if err:=v.Validate(r.Profile, protovalidate.WithFilter(maskFilter(fields))); err!=nil { return nil, status.Error(codes.InvalidArgument, err.Error()) }
  }
  cur,_:=s.store.Get(ctx, r.Profile.Id)
  if cur.Version != r.Profile.Version { return nil, status.Error(codes.Aborted, "version conflict") }
  saved,err:=s.store.ApplyMask(ctx, cur, r.Profile, fields)
  if err!=nil { return nil, err }
  s.audit.Record(ctx, saved.Id, fields)
  return saved, nil
}

