@Post()
async create(@Body() dto:any){
  if(!isValidIban(dto.iban)) throw new BadRequestException('Invalid input');
  const bank=await this.bank.lookupRouting(dto.routing); // no rate limit
  if(!bank) throw new BadRequestException('Invalid input');
  return this.payouts.create(dto);
}

export function ibanValid(iban:string):boolean{
  const s=iban.replace(/\s/g,'').toUpperCase();
  if(!/^[A-Z0-9]{15,34}$/.test(s)) return false;
  const re=s.slice(4)+s.slice(0,4);
  const num=re.replace(/[A-Z]/g,c=>String(c.charCodeAt(0)-55));
  let rem=0; for(const ch of num) rem=(rem*10+(+ch))%97;
  return rem===1;
}

@Post()
async create(@Headers('accept-version') ver:string, @Body() dto:CreatePayoutDto, @Req() req){
  const errs:FieldError[]=[];
  if(!ibanValid(dto.iban)) errs.push({field:'iban',code:'IBAN_CHECKSUM',message:'IBAN checksum failed'});
  if(errs.length) throw new FieldValidationException(errs, ver);
  await this.limiter.consume(`routing:${req.user.id}`, 1); // 10/min
  const bank=await this.bank.lookupRouting(dto.routing);
  if(!bank) throw new FieldValidationException([{field:'routing',code:'ROUTING_NOT_FOUND',message:'Unknown routing number'}], ver);
  return this.payouts.createIdempotent(dto, dto.requestId);
}

@Catch(FieldValidationException)
export class FieldValidationFilter implements ExceptionFilter{
  catch(ex:FieldValidationException, host:ArgumentsHost){
    const res=host.switchToHttp().getResponse();
    if(ex.version==='1'){ return res.status(400).json({error:'Invalid input'}); } // legacy mobile
    return res.status(422).json({ errors: ex.fields });
  }
}

export function usePayoutForm(){
  const [errors,setErrors]=useState<Record<string,string>>({});
