    if(!ibanValid(values.iban)){ setErrors({iban:'IBAN checksum failed'}); return; }
    const r=await fetch('/payouts',{method:'POST',headers:{'accept-version':'2'},body:JSON.stringify({...values,requestId:values.requestId})});
    if(r.status===422){ const {errors}=await r.json(); setErrors(Object.fromEntries(errors.map(e=>[e.field,e.message]))); return; }
  }
  return { errors, submit };
}

