from .normalize import normalize_email
from .verifier import verify_deliverable

def check_email(request):
    email=normalize_email(request.POST.get('email',''))
    if '@' not in email or '.' not in email.split('@')[1]:
        return render(request,'signup/_check.html',{'state':'invalid'})
    cache_key=f'verify:{request.session.session_key}:{email}'
    cached=cache.get(cache_key)
    if cached: return render(request,'signup/_check.html',{'state':cached})
    try:
        ok=verify_deliverable(email, timeout=1.2)  # token-bucket limited inside
        state='deliverable' if ok else 'undeliverable'
    except (TimeoutError, VerifierDown):
        state='unknown'  # fail-open
    cache.set(cache_key,state,300)
    return render(request,'signup/_check.html',{'state':state})

def subscribe(request):
    email=normalize_email(request.POST.get('email',''))
    if '@' not in email:
        return render(request,'signup/_error.html',{'msg':'Enter a valid email'})
    status='verified'
    try:
        status='verified' if verify_deliverable(email, timeout=1.2) else 'undeliverable'
    except (TimeoutError, VerifierDown):
        status='unverified'  # fail-open: still subscribe
    Subscriber.objects.update_or_create(email=email, defaults={'status':status})
    return render(request,'signup/_ok.html',{'status':status})

import time, requests
_bucket={'tokens':100,'ts':time.time()}
class VerifierDown(Exception): pass

def _take():
    now=time.time(); _bucket['tokens']=min(100,_bucket['tokens']+(now-_bucket['ts'])*100); _bucket['ts']=now
    if _bucket['tokens']<1: raise VerifierDown('rate limited')
    _bucket['tokens']-=1

def verify_deliverable(email:str, timeout:float)->bool:
    _take()
    try:
        r=requests.get('https://verifier/api',params={'email':email},timeout=timeout)
    except requests.Timeout: raise TimeoutError()
    if r.status_code>=500: raise VerifierDown()
    return r.json().get('deliverable',False)

