import { create } from 'zustand';
type Cfg={sampleRate:number;version:number};
type Pending={value:number;baseVersion:number;status:'pending'|'conflict'};
export const useFleet=create<{ reported:Record<string,Cfg>; pending:Record<string,Pending>;
  startEdit:(id:string,v:number)=>void; onReport:(id:string,cfg:Cfg,nack?:boolean)=>void; }>((set,get)=>({
  reported:{}, pending:{},
  startEdit:(id,v)=>set(s=>({pending:{...s.pending,[id]:{value:v, baseVersion:s.reported[id].version, status:'pending'}}})),
  onReport:(id,cfg,nack)=>set(s=>{
    const pend=s.pending[id];
    const reported={...s.reported,[id]:cfg};
    if(!pend) return {reported};
    if(nack || cfg.sampleRate!==pend.value){ return {reported, pending:{...s.pending,[id]:{...pend,status:'conflict'}}}; }
    const {[id]:_,...rest}=s.pending; return {reported, pending:rest}; // committed
  })
}));

export async function writeConfig(id:string, sampleRate:number, baseVersion:number){
  const r=await fetch(`/api/devices/${id}/config`,{method:'PUT',headers:{'If-Match':String(baseVersion)},body:JSON.stringify({sampleRate})});
  if(r.status===409){ return {conflict:true, current:await r.json()}; } // CAS failed (peer edited)
  return {accepted:true};
}

export function connectFleet(onReport){
  let ws=new WebSocket('/ws/fleet');
  ws.onmessage=(e)=>{ const m=JSON.parse(e.data); onReport(m.deviceId, m.config, m.nack); };
  ws.onclose=()=>{ setTimeout(()=>{ const fresh=connectFleet(onReport); fresh.requestSnapshot(); },1000); };
  // snapshot merges with pending in the store, not replaces
  return { requestSnapshot:()=>ws.send(JSON.stringify({type:'snapshot'})) };
}

export function DeviceRow({id}:{id:string}){
  const reported=useFleet(s=>s.reported[id]);
  const pending=useFleet(s=>s.pending[id]);
  const startEdit=useFleet(s=>s.startEdit);
  const [val,setVal]=useState(reported.sampleRate);
  async function save(){
    startEdit(id, +val);
    const res=await writeConfig(id, +val, reported.version);
    if('conflict' in res){ useFleet.getState().onReport(id, res.current, true); }
  }
  const shown=pending?.value ?? reported.sampleRate;
  return <tr><td><input value={val} onChange={e=>setVal(e.target.value)}/></td>
    <td>{pending?.status==='pending' && 'syncing…'}{pending?.status==='conflict' && `conflict: device has ${reported.sampleRate}`}</td>
    <td><button onClick={save}>Save</button></td></tr>;
}

