export function validate(formDef, values){
  const errors={};
  for(const f of formDef.fields){
    if(f.required && !values[f.key]) errors[f.key]='required';
    if(f.pattern && !new RegExp(f.pattern).test(values[f.key])) errors[f.key]='invalid';
  }
  return errors; // runs only in browser; server trusts the client
}

export interface FieldDef{ key:string; required?:boolean; pattern?:string; min?:number; max?:number; requiredIf?:{key:string;eq:any} }
export interface Compiled{ test:(v:string)=>boolean }
export function evaluate(fields:FieldDef[], compiled:Record<string,Compiled>, values:any){
  const errors:Record<string,string>={};
  for(const f of fields){
    const req=f.required || (f.requiredIf && values[f.requiredIf.key]===f.requiredIf.eq);
    if(req && (values[f.key]==null||values[f.key]==='')){ errors[f.key]='required'; continue; }
    if(values[f.key]==null) continue;
    if(compiled[f.key] && !compiled[f.key].test(String(values[f.key]))) errors[f.key]='invalid format';
    if(f.min!=null && +values[f.key]<f.min) errors[f.key]='too small';
    if(f.max!=null && +values[f.key]>f.max) errors[f.key]='too large';
  }
  return errors;
}

import RE2 from 're2';
const cache=new Map<string,{compiled:Record<string,any>}>();
export function compileForTenant(tenantId:string, formId:string, version:number, fields:FieldDef[]){
  const key=`${tenantId}:${formId}:${version}`; // tenant-isolated, version-pinned
  const hit=cache.get(key); if(hit) return hit.compiled;
  const compiled:Record<string,any>={};
  for(const f of fields){ if(f.pattern){ compiled[f.key]=new RE2(f.pattern); } } // RE2: linear time, no ReDoS
  cache.set(key,{compiled});
  return compiled;
}

