export class CircuitBreaker{
  private fails=0; private openUntil=0;
  constructor(private threshold=5, private cooldownMs=30000){}
  async run<T>(fn:()=>Promise<T>, fallback:()=>T):Promise<T>{
    if(Date.now()<this.openUntil) return fallback();
    try{ const r=await fn(); this.fails=0; return r; }
    catch(e){ if(++this.fails>=this.threshold) this.openUntil=Date.now()+this.cooldownMs; return fallback(); }
  }
}

import { CircuitBreaker } from '../breaker';
import crypto from 'crypto';
const breaker=new CircuitBreaker();
const seen=new Map<string,Promise<string>>();
export async function precheck(req){
  const { email, phone, ip }=req.body;
  if(!email||!phone) return {verdict:'incomplete'};
  const key=crypto.createHash('sha256').update(email+phone+ip).digest('hex');
  if(seen.has(key)) return { verdict: await seen.get(key)! }; // dedupe identical triples
  const p=breaker.run(async ()=>{ const s=await fraud.score({email,phone,ip}); return s>0.8?'block':s>0.5?'review':'ok'; }, ()=> 'review' /* breaker open -> manual review */);
  seen.set(key, p);
  return { verdict: await p }; // coarse only; no numeric score leaves the server
}

export async function submit(req){
  const verdict=await precheck(req); // reuse, deduped
  if(verdict.verdict==='block') return { status:403, body:{message:'We could not approve this application.'} }; // no reason leaked
  const app=await apps.create({ ...req.body, riskFlag: verdict.verdict==='review' ? 'manual_review' : 'auto' });
  return { status:201, body:{ id:app.id } };
}

