export interface Band{ rowId:string; origin:string; dest:string; min:number; max:number }
export function findOverlaps(bands:Band[]):string[]{
  const bad=new Set<string>();
  const byPair=new Map<string,Band[]>();
  for(const b of bands){ const k=b.origin+'>'+b.dest; (byPair.get(k)??byPair.set(k,[]).get(k)!).push(b); }
  for(const group of byPair.values()){
    group.sort((a,b)=>a.min-b.min);
    for(let i=1;i<group.length;i++){ if(group[i].min < group[i-1].max){ bad.add(group[i].rowId); bad.add(group[i-1].rowId); } }
  }
  return [...bad];
}

import { useRef, useState } from 'react';
import { useDebouncedCallback } from 'use-debounce';
import { findOverlaps } from './overlap';
export function useRateEdits(initial, tableVersion){
  const [rows,setRows]=useState(initial);
  const dirty=useRef(new Map<string,any>());
  const [rowErrors,setRowErrors]=useState<Record<string,string>>({});
  const flush=useDebouncedCallback(async ()=>{
    const edits=[...dirty.current.entries()].map(([rowId,patch])=>({rowId,patch}));
    const r=await fetch('/api/rates/batch',{method:'PATCH',headers:{'If-Match':String(tableVersion.current)},body:JSON.stringify({edits})});
    if(r.status===409){ setRowErrors({_:'Table changed; reload'}); return; }
    const { results, version }=await r.json(); tableVersion.current=version;
    const errs:Record<string,string>={};
    setRows(prev=>prev.map(row=>{ const res=results.find(x=>x.rowId===row.id); if(res&&!res.ok){ errs[row.id]=res.error; return res.previous; } return row; }));
    setRowErrors(errs); dirty.current.clear();
  },800);
  function edit(rowId, field, value){
    setRows(prev=>{ const next=prev.map(r=>r.id===rowId?{...r,[field]:value}:r); const over=findOverlaps(next.map(toBand)); setRowErrors(Object.fromEntries(over.map(id=>[id,'Overlapping band']))); return next; });
    dirty.current.set(rowId,{...(dirty.current.get(rowId)||{}),[field]:value}); flush();
  }
  return { rows, rowErrors, edit };
}

import { findOverlaps } from '../overlap';
export async function patchBatch(req){
  const ifMatch=Number(req.headers['if-match']);
  return db.tx(async t=>{
    const table=await t.rateTable.lock(req.tableId);
    if(table.version!==ifMatch) return { status:409 }; // optimistic lock
    const results=[];
    for(const e of req.body.edits){
      const prev=await t.rate.get(e.rowId);
      await t.rate.update(e.rowId, e.patch);
      results.push({rowId:e.rowId, prev});
    }
    const all=await t.rate.allBands(req.tableId);
    const bad=new Set(findOverlaps(all)); // authoritative overlap check
    for(const r of results){ if(bad.has(r.rowId)){ await t.rate.update(r.rowId, r.prev); } } // rollback only failed rows
    const newVersion=await t.rateTable.bump(req.tableId);
    return { status:200, body:{ version:newVersion, results: results.map(r=>({rowId:r.rowId, ok:!bad.has(r.rowId), error: bad.has(r.rowId)?'Overlapping band':undefined, previous:r.prev})) } };
  });
}

