export interface Variant{ sku:string; options:Record<string,string> }
export function buildResolver(variants:Variant[]){
  const index=new Map<string,string>();
  for(const v of variants){ index.set(keyOf(v.options), v.sku); }
  return {
    resolve:(sel:Record<string,string>)=> index.get(keyOf(sel)) ?? null,
    allowedFor:(name:string, partial:Record<string,string>)=>{
      const vals=new Set<string>();
      for(const v of variants){ if(Object.entries(partial).every(([k,val])=>k===name||v.options[k]===val)) vals.add(v.options[name]); }
      return vals; // only options that keep a real SKU reachable
    }
  };
}
function keyOf(o:Record<string,string>){ return Object.keys(o).sort().map(k=>k+'='+o[k]).join('|'); }

const cache=new Map<string,{at:number;qty:number}>();
const inflight=new Map<string,Promise<number>>();
async function fetchStock(sku:string){
  const hit=cache.get(sku); if(hit && Date.now()-hit.at<10000) return hit.qty;
  if(inflight.has(sku)) return inflight.get(sku)!;
  const p=fetch('/api/inventory/'+sku).then(r=>r.json()).then(j=>{ cache.set(sku,{at:Date.now(),qty:j.qty}); inflight.delete(sku); return j.qty; });
  inflight.set(sku,p); return p;
}
export function useStock(){
  const [qty,setQty]=useState<number|null>(null);
  const check=useDebouncedCallback(async (sku:string|null)=>{ if(!sku){ setQty(null); return; } setQty(await fetchStock(sku)); },200);
  return { qty, check };
}

