  useEffect(()=>{ check(sku); },[sku]);
  const optionNames=Object.keys(variants[0].options);
  return <>{optionNames.map(name=>{ const allowed=resolver.allowedFor(name, omit(sel,name));
    return <Select key={name} value={sel[name]} options={[...allowed]} onChange={v=>setSel({...sel,[name]:v})}/>; })}
