export interface Policy{ minLen:number; classes:number; banlist:string[] }
export function evaluatePolicy(pw:string, p:Policy){
  const issues:string[]=[];
  if(pw.length<p.minLen) issues.push(`At least ${p.minLen} characters`);
  const classes=[/[a-z]/,/[A-Z]/,/\d/,/[^a-zA-Z0-9]/].filter(re=>re.test(pw)).length;
  if(classes<p.classes) issues.push(`Use at least ${p.classes} character types`);
  if(p.banlist.includes(pw.toLowerCase())) issues.push('This password is too common');
  return issues;
}

export async function breachCount(pw:string):Promise<number>{
  const data=new TextEncoder().encode(pw);
  const buf=await crypto.subtle.digest('SHA-1', data);
  const hex=[...new Uint8Array(buf)].map(b=>b.toString(16).padStart(2,'0')).join('').toUpperCase();
  const prefix=hex.slice(0,5), suffix=hex.slice(5); // k-anonymity: only prefix leaves the device
  const res=await fetch('https://api.pwnedpasswords.com/range/'+prefix);
  const body=await res.text();
  const line=body.split('\n').find(l=>l.startsWith(suffix));
  return line? parseInt(line.split(':')[1],10): 0;
}

