import { redis } from '@/lib/redis';
export async function holdSlot(slotId:string, sessionId:string){
  const ok=await redis.set('hold:'+slotId, sessionId, { NX:true, EX:480 }); // 8 min distributed hold
  return ok==='OK';
}
const CONFIRM=`if redis.call('get',KEYS[1])==ARGV[1] then redis.call('del',KEYS[1]); return 1 else return 0 end`;
export async function confirmHold(slotId:string, sessionId:string){
  return (await redis.eval(CONFIRM,{keys:['hold:'+slotId],arguments:[sessionId]}))===1; // atomic: only the holder converts
}
export async function releaseHold(slotId:string, sessionId:string){
  const CTX=`if redis.call('get',KEYS[1])==ARGV[1] then return redis.call('del',KEYS[1]) else return 0 end`;
  await redis.eval(CTX,{keys:['hold:'+slotId],arguments:[sessionId]});
}

import { confirmHold } from '../holds';
export async function book(req){
  const { slotId, insurance, sessionId }=req.body;
  const elig=await insuranceCheck(insurance); // re-check authoritatively
  if(!elig.ok) return { status:422, body:{ field:'insurance', error:elig.reason } };
  const converted=await confirmHold(slotId, sessionId);
  if(!converted) return { status:409, body:{ field:'slot', error:'Your hold expired; please pick another time' } };
  await db.appointment.create({ slotId, patient:req.user, insurance }); // slot freed from Redis, now persisted
  return { status:201 };
}

