func ValidateCoupons(cart Cart, coupons []Coupon) error {
  for _, c := range coupons {
    if c.Type == "percent" {
      for _, o := range coupons {
        if o.Type == "percent" && o.Code != c.Code {
          // accidentally allows two percent coupons in some orderings
          if c.Stackable { continue }
          return fmt.Errorf("cannot stack")
        }
      }
    }
  }
  return nil // eligibility never checked
}

package checkout

type Violation struct{ RuleID, Message string; Codes []string }

type SetRule interface{ ID() string; Check(coupons []Coupon) *Violation }

type AtMostOneOfType struct{ T string }
func (r AtMostOneOfType) ID() string { return "at_most_one_"+r.T }
func (r AtMostOneOfType) Check(cs []Coupon) *Violation {
  var hit []string
  for _, c := range cs { if c.Type==r.T { hit=append(hit, c.Code) } }
  if len(hit)>1 { return &Violation{r.ID(), "Only one "+r.T+" coupon allowed", hit} }
  return nil // deterministic: depends only on the set, not iteration order
}

type MutuallyExclusive struct{ A, B string }
func (r MutuallyExclusive) ID() string { return "mutex_"+r.A+"_"+r.B }
func (r MutuallyExclusive) Check(cs []Coupon) *Violation {
  has:=map[string]bool{}
  for _, c := range cs { has[c.Code]=true }
  if has[r.A] && has[r.B] { return &Violation{r.ID(), r.A+" and "+r.B+" cannot combine", []string{r.A,r.B}} }
  return nil
}

var Rules = []SetRule{ AtMostOneOfType{"percent"}, MutuallyExclusive{"WELCOME10","BLACKFRIDAY"} }

package checkout
import "golang.org/x/sync/errgroup"

func CheckEligibility(ctx context.Context, user User, cs []Coupon, svc EligSvc) (map[string]string, error) {
  res := make(map[string]string, len(cs))
  var mu sync.Mutex
  g, ctx := errgroup.WithContext(ctx)
  for _, c := range cs {
    c := c
    g.Go(func() error {
      ok, reason, err := svc.Eligible(ctx, user, c) // async, in parallel
      if err != nil { return err }
      if !ok { mu.Lock(); res[c.Code]=reason; mu.Unlock() }
      return nil
    })
  }
  return res, g.Wait()
}

package checkout

func ValidateCoupons(ctx context.Context, user User, cart Cart, cs []Coupon, svc EligSvc) (Response, error) {
  var vs []Violation
  inelig, err := CheckEligibility(ctx, user, cs, svc)
  if err != nil { return Response{}, err }
  for code, reason := range inelig { vs = append(vs, Violation{"eligibility", reason, []string{code}}) }
  for _, r := range Rules { if v := r.Check(cs); v != nil { vs = append(vs, *v) } }
  // backward-compatible: keep Valid bool, ADD Violations
  return Response{ Valid: len(vs)==0, Violations: vs }, nil
}

