import { create } from 'zustand';
type Op={ id:string; kind:'add'|'remove'; label:string };
export const useLabels=create<{ labels:Set<string>; pending:Map<string,Op>;
  applyLocal:(op:Op)=>void; confirm:(opId:string)=>void; rollback:(opId:string)=>void; mergeRemote:(op:Op)=>void; }>((set)=>({
  labels:new Set(), pending:new Map(),
  applyLocal:(op)=>set(s=>{ const labels=new Set(s.labels); op.kind==='add'?labels.add(op.label):labels.delete(op.label); const pending=new Map(s.pending); pending.set(op.id,op); return {labels,pending}; }),
  confirm:(opId)=>set(s=>{ const pending=new Map(s.pending); pending.delete(opId); return {pending}; }),
  rollback:(opId)=>set(s=>{ const op=s.pending.get(opId); if(!op) return {}; const labels=new Set(s.labels); op.kind==='add'?labels.delete(op.label):labels.add(op.label); const pending=new Map(s.pending); pending.delete(opId); return {labels,pending}; }),
  mergeRemote:(op)=>set(s=>{ const labels=new Set(s.labels); op.kind==='add'?labels.add(op.label):labels.delete(op.label); return {labels}; }) // merges, never replaces
}));

export async function sendOp(issueId:string, op:{id:string;kind:string;label:string}){
  const r=await fetch(`/api/issues/${issueId}/labels/ops`,{method:'POST',headers:{'Idempotency-Key':op.id},body:JSON.stringify(op)});
  if(r.status===403) return { ok:false, reason:'No permission for this label' };
  if(r.status===409) return { ok:false, reason:'Label is archived' };
  return { ok:true };
}

export async function applyOp(req){
  const op=req.body; const key=req.headers['idempotency-key'];
  if(await db.opLog.seen(key)) return { status:200 }; // idempotent: replay/double-add is a no-op
  const label=await db.label.get(op.label);
  if(label?.archived) return { status:409 };
  if(!await perms.canLabel(req.user, op.label)) return { status:403 };
  await db.issueLabel.apply(req.params.id, op); // add/remove
  await db.opLog.record(key);
  if(op.label==='security' && op.kind==='add') await jobs.enqueue('notify-security', req.params.id); // automation async, decoupled
  ws.broadcast(req.params.id, op); // teammates merge this op
  return { status:200 };
}

export function Labels({issueId}:{issueId:string}){
  const { labels, applyLocal, confirm, rollback }=useLabels();
  async function add(label:string){
    const op={ id:crypto.randomUUID(), kind:'add' as const, label };
    applyLocal(op);
    const res=await sendOp(issueId, op);
    res.ok ? confirm(op.id) : rollback(op.id);
    if(!res.ok) toast(res.reason);
  }
  return <>{[...labels].map(l=><Chip key={l}>{l}</Chip>)}<AddLabel onAdd={add}/></>;
}

