type ValidatorCfg={ fn:(v:string, signal:AbortSignal)=>Promise<{ok:boolean;message?:string}>; concurrency:number; failOpen:boolean };
export class AsyncValidationEngine{
  private gen=new Map<string,number>();
  private inflight=new Map<string,Promise<any>>();
  private running=new Map<string,number>();
  constructor(private validators:Record<string,ValidatorCfg>){}
  async validate(field:string, value:string):Promise<{ok:boolean;message?:string}>{
    const cfg=this.validators[field];
    const myGen=(this.gen.get(field)||0)+1; this.gen.set(field,myGen);
    const key=field+':'+value;
    if(this.inflight.has(key)) return this.guard(field,myGen, await this.inflight.get(key)!);
    while((this.running.get(field)||0)>=cfg.concurrency) await new Promise(r=>setTimeout(r,15)); // per-validator cap
    const ac=new AbortController();
    this.running.set(field,(this.running.get(field)||0)+1);
    const p=cfg.fn(value, ac.signal).catch(()=> cfg.failOpen? {ok:true} : {ok:false, message:'Could not verify'})
      .finally(()=>{ this.running.set(field,(this.running.get(field)||1)-1); this.inflight.delete(key); });
    this.inflight.set(key,p);
    return this.guard(field, myGen, await p);
  }
  private guard(field:string, myGen:number, res:any){ return this.gen.get(field)===myGen ? res : { ok:true, stale:true }; }
}

