const RESERVE=`local rem=tonumber(redis.call('get',KEYS[1]) or '0')
if rem < tonumber(ARGV[1]) then return -1 end
redis.call('decrby',KEYS[1],ARGV[1])
redis.call('setex',KEYS[2],600,ARGV[1])
return rem-ARGV[1]`;
export async function reserve(redis, wh:string, date:string, sessionId:string, pallets:number){
  const r=await redis.eval(RESERVE,{keys:[`cap:${wh}:${date}`,`hold:${wh}:${date}:${sessionId}`],arguments:[String(pallets)]});
  return r===-1 ? { ok:false } : { ok:true, remaining:Number(r) }; // atomic decrement-or-refuse
}
export async function release(redis, wh:string, date:string, sessionId:string){
  const held=await redis.getdel(`hold:${wh}:${date}:${sessionId}`);
  if(held) await redis.incrby(`cap:${wh}:${date}`, Number(held)); // return capacity
}

