@Post('reserve/adjust')
async adjust(@Body() b, @Session() s){ await release(this.redis, b.warehouse, b.date, s.id); return reserve(this.redis, b.warehouse, b.date, s.id, b.pallets); } // atomic re-reserve
@Post('confirm')
async confirm(@Body() b, @Session() s){
  const held=await this.redis.get(`hold:${b.warehouse}:${b.date}:${s.id}`);
  if(!held) throw new ConflictException('Reservation expired');
