export function useClanSave(clan){
  const [name,setName]=useState(clan.name);
  const [status,setStatus]=useState<'idle'|'saving'|'rejected'|'pending'|'conflict'>('idle');
  async function save(){
    const parsed=nameSchema.safeParse({name});
    if(!parsed.success){ setStatus('rejected'); return; } // instant banlist/format reject
    const prev=clan.name; setStatus('saving');
    const r=await fetch(`/api/clans/${clan.id}`,{method:'PUT',headers:{'If-Match':String(clan.version)},body:JSON.stringify({name})});
    if(r.status===409){ setName(prev); setStatus('conflict'); return; }
    const j=await r.json();
    if(j.moderation==='rejected'){ setName(prev); setStatus('rejected'); return; } // rollback
    setStatus(j.moderation==='pending'?'pending':'idle'); clan.version=j.version;
  }
  return { name, setName, status, save };
}

import { nameSchema } from '../nameRules';
export async function updateClan(req){
  if(Number(req.headers['if-match'])!==await db.clan.version(req.params.id)) return { status:409 };
  const parsed=nameSchema.safeParse(req.body);
  if(!parsed.success) return { status:422, body:{ field:'name', moderation:'rejected', error:parsed.error.issues[0].message } };
  let moderation='approved';
  try{ const ok=await withTimeout(ai.moderate(req.body.name), 1200); if(!ok) moderation='rejected'; }
  catch{ moderation='pending'; } // timeout -> flagged, never silent allow
  if(moderation==='rejected') return { status:422, body:{ field:'name', moderation:'rejected' } };
  const version=await db.clan.update(req.params.id, { name:req.body.name, moderation });
  return { status:200, body:{ moderation, version } };
}

