export interface Sku{ minQty:number; maxQty:number; packSize:number; tiers:{min:number;price:number}[] }
export function normalizeQty(sku:Sku, q:number){
  const clamped=Math.min(sku.maxQty, Math.max(sku.minQty, q));
  return Math.round(clamped / sku.packSize) * sku.packSize; // snap to pack multiple
}
export function tierPrice(sku:Sku, q:number){
  const t=[...sku.tiers].sort((a,b)=>b.min-a.min).find(t=>q>=t.min) ?? sku.tiers[0];
  return t.price * q;
}

