  setQty:(id:string,sku:any,q:number)=>void; reconcile:(id:string,seq:number,total:number)=>void; }>((set,get)=>({
  lines:{},
  setQty:(id,sku,q)=>set(s=>{ const nq=normalizeQty(sku,q); const line=s.lines[id]; return { lines:{...s.lines,[id]:{ qty:nq, estimate:tierPrice(sku,nq), total:line.total, seq:line.seq+1 }} }; }),
  reconcile:(id,seq,total)=>set(s=>{ const line=s.lines[id]; if(seq!==line.seq) return {}; /* stale response ignored */ return { lines:{...s.lines,[id]:{...line,total}} }; })
}));

export function useLineRecompute(){
  const reconcile=useCart(s=>s.reconcile);
  const debounced=useMemo(()=>new Map<string,ReturnType<typeof debounce>>(),[]);
  return (lineId:string, qty:number, seq:number)=>{
    if(!debounced.has(lineId)) debounced.set(lineId, debounce(async (q,sq)=>{ const res=await trpc.cart.recompute.mutate({lineId, qty:q}); reconcile(lineId, sq, res.total); },400));
    debounced.get(lineId)!(qty, seq);
  };
}

import { normalizeQty, tierPrice } from '../cart/qtyRules';
export const recompute = procedure.input(z.object({lineId:z.string(),qty:z.number()})).mutation(async ({input})=>{
  const sku=await db.sku.forLine(input.lineId);
  const qty=normalizeQty(sku, input.qty); // server re-snaps to pack size (authoritative)
  const base=tierPrice(sku, qty);
  const tax=await tax.for(sku, qty); const freight=await freight.for(sku, qty);
  await db.cartLine.update(input.lineId, { qty });
  return { qty, total: base + tax + freight }; // authoritative total
});

