function isBreaking(oldS:any, newS:any){
  const newReq=new Set(newS.required); const oldReq=new Set(oldS.required);
  for(const r of newReq) if(!oldReq.has(r)) return true; // new required field is breaking
  for(const k of Object.keys(oldS.properties)) if(!newS.properties[k]) return true; // removed field is breaking
  return false;
}
test('no breaking change without major bump', ()=>{
  const major=(s:string)=>s.split('.')[0];
  if(isBreaking(prev, applicantSchema)) expect(major(APPLICANT_SCHEMA_VERSION)).not.toBe(major('2.2.0'));
});

func Purchase(ctx context.Context, seats []string, buyer string) error {
  for _, s := range seats {
    sold, _ := store.IsSold(ctx, s)
    if sold { return fmt.Errorf("seat %s taken", s) } // checked only at purchase
  }
  return store.MarkSold(ctx, seats, buyer) // race: two buyers both pass IsSold
}

// unique partial index: CREATE UNIQUE INDEX ON seat_holds(event_id, seat_id) WHERE status IN ('held','sold')
func HoldSeat(ctx context.Context, db *sql.DB, eventID, seat, session string) (bool, error) {
  res, err := db.ExecContext(ctx, `INSERT INTO seat_holds(event_id, seat_id, session_id, status, expires_at)
    VALUES($1,$2,$3,'held', now()+interval '7 minutes')
    ON CONFLICT (event_id, seat_id) WHERE status IN ('held','sold') DO NOTHING`, eventID, seat, session)
  if err != nil { return false, err }
  n, _ := res.RowsAffected()
  return n == 1, nil // atomic claim-or-fail at selection time
}

func Purchase(ctx context.Context, db *sql.DB, seats []string, session, buyer string) error {
  sort.Strings(seats) // deterministic order -> deadlock-free
  tx, _ := db.BeginTx(ctx, nil)
  defer tx.Rollback()
  for _, s := range seats {
    var owner string; var exp time.Time
    err := tx.QueryRowContext(ctx, `SELECT session_id, expires_at FROM seat_holds WHERE event_id=$1 AND seat_id=$2 AND status='held' FOR UPDATE`, eventID, s).Scan(&owner, &exp)
    if err != nil || owner != session || time.Now().After(exp) {
      return fmt.Errorf("seat %s no longer held by you", s) // all-or-nothing: tx rolls back
    }
  }
  _, err := tx.ExecContext(ctx, `UPDATE seat_holds SET status='sold', buyer_id=$1 WHERE event_id=$2 AND seat_id=ANY($3) AND session_id=$4`, buyer, eventID, pq.Array(seats), session)
  if err != nil { return err }
  return tx.Commit()
}

func SweepExpired(ctx context.Context, db *sql.DB) {
  for range time.Tick(30 * time.Second) {
    db.ExecContext(ctx, `DELETE FROM seat_holds WHERE status='held' AND expires_at < now()`) // free expired
    bus.Publish("seats.freed") // map refresh
  }
}

export function useSeatMap(eventId:string){
  const [states,setStates]=useState<Record<string,'free'|'held'|'sold'>>({});
  useEffect(()=>{ const ws=new WebSocket('/ws/seats/'+eventId); ws.onmessage=e=>setStates(s=>({...s,...JSON.parse(e.data)})); return ()=>ws.close(); },[eventId]);
  async function select(seat:string){ const r=await fetch('/api/seats/hold',{method:'POST',body:JSON.stringify({eventId,seat})}); if(!r.ok) setStates(s=>({...s,[seat]:'held'})); /* someone beat us */ }
  return { states, select };
}

export interface Cond{ qid:string; op:'eq'|'neq'|'in'; value:any }
export interface Rule{ all?:Cond[]; any?:Cond[]; show?:string[]; hide?:string[] }
function matches(c:Cond, answers:any){ const a=answers[c.qid]; return c.op==='eq'?a===c.value:c.op==='neq'?a!==c.value:Array.isArray(c.value)&&c.value.includes(a); }
function ruleActive(r:Rule, answers:any){ return (r.all? r.all.every(c=>matches(c,answers)):true) && (r.any? r.any.some(c=>matches(c,answers)):true); }
export function activeQuestions(allQ:string[], rules:Rule[], answers:any):Set<string>{
  const visible=new Set(allQ);
  for(const r of rules){ if(ruleActive(r, answers)){ r.hide?.forEach(q=>visible.delete(q)); r.show?.forEach(q=>visible.add(q)); } }
  return visible; // single pass, O(rules)
}

import { activeQuestions } from './branching';
export function validateSurvey(survey, answers){
  const visible=activeQuestions(survey.questions.map(q=>q.id), survey.rules, answers);
  const errors:Record<string,string>={};
  for(const q of survey.questions){
    if(!visible.has(q.id)) continue; // skipped questions are NOT required
    if(q.required && (answers[q.id]==null || answers[q.id]==='')) errors[q.id]='Required';
  }
  return errors;
}

import { validateSurvey } from '../validate';
export async function submitSurvey(req){
  const survey=await db.survey.versioned(req.params.id, req.body.version);
  const errors=validateSurvey(survey, req.body.answers); // identical engine, authoritative
  if(Object.keys(errors).length) return { status:422, body:{ errors } };
  await db.response.create({ surveyId:req.params.id, version:req.body.version, answers:req.body.answers });
  return { status:201 };
}

