});

const ALLOWED=['application/pdf','application/msword']; const MAX=50*1024*1024;
export function useUpload(){
  const [status,setStatus]=useState<'idle'|'invalid'|'uploading'|'scanning'|'clean'|'infected'>('idle');
  async function upload(file:File){
    if(!ALLOWED.includes(file.type)){ setStatus('invalid'); return; } // reject before bytes leave
    if(file.size>MAX){ setStatus('invalid'); return; }
    setStatus('uploading');
    const fd=new FormData(); fd.append('file', file);
    const r=await fetch('/docs',{method:'POST',body:fd});
    const j=await r.json(); setStatus('scanning'); // optimistic preview shown, marked scanning
    pollScan(j.docId, setStatus);
  }
  return { status, upload };
}

import { fileTypeFromBuffer } from 'file-type';
app.post('/docs', upload.single('file'), async (req,res)=>{
  const head=req.file.buffer.subarray(0, 4100);
  const ft=await fileTypeFromBuffer(head); // magic bytes, not extension
  if(!ft || !['pdf','doc','docx'].includes(ft.ext)) return res.status(415).json({ error:'unsupported_type' });
  const key=`docs/${crypto.randomUUID()}`;
  await s3.upload({ Bucket:'docs', Key:key, Body:req.file.buffer }).promise();
  const doc=await db.doc.create({ key, status:'pending_scan', owner:req.user.id });
  await scanQueue.add('scan',{ docId:doc.id, key }); // async virus scan
  res.json({ docId:doc.id, status:'pending_scan' });
});

scanQueue.process('scan', async (job)=>{
  const { docId, key }=job.data;
  const obj=await s3.getObject({ Bucket:'docs', Key:key }).promise();
  const verdict=await clamav.scan(obj.Body); // ClamAV
  if(verdict.isInfected){
    await s3.copyObject({ Bucket:'docs', CopySource:`docs/${key}`, Key:`quarantine/${key}` }).promise();
    await s3.deleteObject({ Bucket:'docs', Key:key }).promise();
    await db.doc.update(docId,{ status:'quarantined' });
    notify(docId,'infected');
  } else {
    await db.doc.update(docId,{ status:'clean' }); // now usable
  }
});

app.get('/docs/:id', async (req,res)=>{
  const doc=await db.doc.get(req.params.id);
  if(doc.status==='quarantined') return res.status(451).send('quarantined');
  if(doc.status==='pending_scan') return res.status(425).send('scanning'); // too-early
  const url=await s3.signed(doc.key); // only clean (or legacy-clean) served
  res.redirect(url);
});
